            Spacer(Modifier.width(10.dp))
            Column {
                Text(
                    text = if (isTutor) "+$amount credits earned!" else "$amount credits used",
                    fontSize = 18.sp,
                    fontWeight = FontWeight.Bold,
                    color = if (isTutor) Color(0xFF38A169) else Color(0xFFED8936)
                )
                Text(
