package com.example.learnloop.ui.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.learnloop.data.repository.LearnLoopRepository
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharedFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asSharedFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.collectLatest
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

data class EditProfileUiState(
    val name: String = "",
    val bio: String = "",
    val institutionEmail: String = ""
)

sealed class EditProfileEvent {
    object NavigateBack : EditProfileEvent()
}

class EditProfileViewModel(
    private val repository: LearnLoopRepository
) : ViewModel() {
    private val _uiState = MutableStateFlow(EditProfileUiState())
    val uiState: StateFlow<EditProfileUiState> = _uiState.asStateFlow()

    private val _events = MutableSharedFlow<EditProfileEvent>()
    val events: SharedFlow<EditProfileEvent> = _events.asSharedFlow()

    private var initialized = false

    init {
        viewModelScope.launch {
            repository.currentUser.collectLatest { user ->
                if (!initialized) {
                    _uiState.update {
                        it.copy(
                            name = user.name,
                            bio = user.bio.orEmpty(),
                            institutionEmail = user.institutionEmail
                        )
                    }
                    initialized = true
                }
            }
        }
    }

    fun onNameChange(value: String) {
        _uiState.update { it.copy(name = value) }
    }

    fun onBioChange(value: String) {
        _uiState.update { it.copy(bio = value) }
    }

    fun onInstitutionEmailChange(value: String) {
        _uiState.update { it.copy(institutionEmail = value) }
    }

    fun onSave() {
        val state = _uiState.value
        viewModelScope.launch {
            repository.updateProfile(state.name, state.bio, state.institutionEmail)
            _events.emit(EditProfileEvent.NavigateBack)
        }
    }
}

package com.example.learnloop.ui.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.learnloop.data.models.Session
import com.example.learnloop.data.repository.LearnLoopRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.stateIn

data class MySessionsUiState(
    val selectedTab: Int = 1,
    val tabs: List<String> = listOf("Upcoming", "Active", "Completed"),
    val upcoming: List<Session> = emptyList(),
    val active: List<Session> = emptyList(),
    val completed: List<Session> = emptyList(),
    val sessionsToShow: List<Session> = emptyList()
)

class MySessionsViewModel(
    repository: LearnLoopRepository
) : ViewModel() {
    private val selectedTab = MutableStateFlow(1)

    val uiState: StateFlow<MySessionsUiState> = combine(
        repository.activeSessions,
        repository.completedSessions,
        selectedTab
    ) { activeSessions, completedSessions, tab ->
        val upcoming = activeSessions.filter { it.status == "SCHEDULED" }
        val active = activeSessions.filter { it.status == "ACTIVE" }
        val completed = completedSessions
        val sessionsToShow = when (tab) {
            0 -> upcoming
            1 -> active
            else -> completed
        }
        MySessionsUiState(
            selectedTab = tab,
            upcoming = upcoming,
            active = active,
            completed = completed,
            sessionsToShow = sessionsToShow
        )
    }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), MySessionsUiState())

    fun onTabSelected(index: Int) {
        selectedTab.value = index
    }
}

package com.example.learnloop.ui.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.learnloop.data.models.Notification
import com.example.learnloop.data.repository.LearnLoopRepository
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch

data class NotificationsUiState(
    val notifications: List<Notification> = emptyList(),
    val unreadCount: Int = 0
)

class NotificationsViewModel(
    private val repository: LearnLoopRepository
) : ViewModel() {
    val uiState: StateFlow<NotificationsUiState> = repository.notifications
        .map { notifications ->
            NotificationsUiState(
                notifications = notifications,
                unreadCount = notifications.count { !it.isRead }
            )
        }
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), NotificationsUiState())

    fun markAllRead() {
        viewModelScope.launch {
            repository.markAllNotificationsRead()
        }
    }
}

package com.example.learnloop.ui.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.learnloop.data.models.User
import com.example.learnloop.data.repository.LearnLoopRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch

data class PostRequestUiState(
    val step: Int = 0,
    val selectedSubject: String = "",
    val topic: String = "",
    val description: String = "",
    val urgency: String = "MEDIUM",
    val duration: Int = 30,
    val language: String = "English",
    val isLanguageMenuExpanded: Boolean = false,
    val subjects: List<String> = emptyList(),
    val languages: List<String> = emptyList(),
    val creditCost: Int = 1,
    val userBalance: Int = 0,
    val matchedTutors: List<User> = emptyList(),
    val isNextEnabled: Boolean = true
)

class PostRequestViewModel(
    private val repository: LearnLoopRepository
) : ViewModel() {
    private val step = MutableStateFlow(0)
    private val selectedSubject = MutableStateFlow("")
    private val topic = MutableStateFlow("")
    private val description = MutableStateFlow("")
    private val urgency = MutableStateFlow("MEDIUM")
    private val duration = MutableStateFlow(30)
    private val language = MutableStateFlow("English")
    private val isLanguageMenuExpanded = MutableStateFlow(false)
    private val creditCost = MutableStateFlow(1)
    private val matchedTutors = MutableStateFlow<List<User>>(emptyList())

    init {
        viewModelScope.launch {
            combine(duration, urgency) { mins, level ->
                repository.estimateCreditCost(mins, level)
            }.collect { cost ->
                creditCost.value = cost
            }
        }
        viewModelScope.launch {
            matchedTutors.value = repository.matchedTutors()
        }
    }

    val uiState: StateFlow<PostRequestUiState> = combine(
        step,
        selectedSubject,
        topic,
        description,
        urgency,
        duration,
        language,
        isLanguageMenuExpanded,
        repository.subjects,
        repository.languages,
        creditCost,
        repository.currentUser,
        matchedTutors
    ) { values ->
        val stepValue = values[0] as Int
        val subjectValue = values[1] as String
        val topicValue = values[2] as String
        val descriptionValue = values[3] as String
        val urgencyValue = values[4] as String
        val durationValue = values[5] as Int
        val languageValue = values[6] as String
        val menuExpandedValue = values[7] as Boolean
        val subjectsValue = values[8] as List<String>
        val languagesValue = values[9] as List<String>
        val costValue = values[10] as Int
        val userValue = values[11] as com.example.learnloop.data.models.User
        val tutorsValue = values[12] as List<User>
        val isNextEnabled = !(stepValue == 2 && userValue.knowledgeCredits < costValue)
        PostRequestUiState(
            step = stepValue,
            selectedSubject = subjectValue,
            topic = topicValue,
            description = descriptionValue,
            urgency = urgencyValue,
            duration = durationValue,
            language = languageValue,
            isLanguageMenuExpanded = menuExpandedValue,
            subjects = subjectsValue,
            languages = languagesValue,
            creditCost = costValue,
            userBalance = userValue.knowledgeCredits,
            matchedTutors = tutorsValue,
            isNextEnabled = isNextEnabled
        )
    }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), PostRequestUiState())

    fun onStepChange(value: Int) {
        step.value = value
    }

    fun onSubjectSelected(value: String) {
        selectedSubject.value = value
    }

    fun onTopicChange(value: String) {
        topic.value = value
    }

    fun onDescriptionChange(value: String) {
        description.value = value
    }

    fun onUrgencyChange(value: String) {
        urgency.value = value
    }

    fun onDurationChange(value: Int) {
        duration.value = value
    }

    fun onLanguageChange(value: String) {
        language.value = value
    }

    fun onLanguageMenuChange(expanded: Boolean) {
        isLanguageMenuExpanded.value = expanded
    }
}

package com.example.learnloop.ui.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.learnloop.data.models.ChatMessage
import com.example.learnloop.data.repository.LearnLoopRepository
import kotlinx.coroutines.Job
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.collectLatest
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

data class SessionRoomUiState(
    val sessionId: String = "",
    val selectedTab: Int = 0,
    val showEndDialog: Boolean = false,
    val elapsedSeconds: Int = 0,
    val currentUserId: String = "u1",
    val otherUserName: String = "Rahul Gupta",
    val messages: List<ChatMessage> = emptyList(),
    val inputText: String = "",
    val isCodeMode: Boolean = false,
    val whiteboardContent: String = "",
    val notes: String = ""
)

class SessionRoomViewModel(
    private val repository: LearnLoopRepository
) : ViewModel() {
    private val _uiState = MutableStateFlow(SessionRoomUiState())
    val uiState: StateFlow<SessionRoomUiState> = _uiState.asStateFlow()

    private var chatJob: Job? = null

    init {
        viewModelScope.launch {
            while (true) {
                delay(1000)
                _uiState.update { it.copy(elapsedSeconds = it.elapsedSeconds + 1) }
            }
        }
    }

    fun setSessionId(sessionId: String) {
        if (_uiState.value.sessionId == sessionId) return
        _uiState.update { it.copy(sessionId = sessionId) }
        chatJob?.cancel()
        chatJob = viewModelScope.launch {
            repository.chatMessages(sessionId).collectLatest { messages ->
                _uiState.update { it.copy(messages = messages) }
            }
        }
    }

    fun onTabSelected(index: Int) {
        _uiState.update { it.copy(selectedTab = index) }
    }

    fun onToggleEndDialog(show: Boolean) {
        _uiState.update { it.copy(showEndDialog = show) }
    }

    fun onInputChange(value: String) {
        _uiState.update { it.copy(inputText = value) }
    }

    fun onToggleCodeMode() {
        _uiState.update { it.copy(isCodeMode = !it.isCodeMode) }
    }

    fun onSendMessage() {
        val state = _uiState.value
        if (state.inputText.isBlank() || state.sessionId.isBlank()) return
        val message = ChatMessage(
            id = "m${state.messages.size + 1}",
            senderId = state.currentUserId,
            senderName = "Alex Johnson",
            content = state.inputText,
            type = if (state.isCodeMode) "CODE" else "TEXT",
            timestamp = "Now"
        )
        viewModelScope.launch {
            repository.sendChatMessage(state.sessionId, message)
        }
        _uiState.update { it.copy(inputText = "") }
    }

    fun onWhiteboardChange(value: String) {
        _uiState.update { it.copy(whiteboardContent = value) }
    }

    fun onNotesChange(value: String) {
        _uiState.update { it.copy(notes = value) }
    }
}

package com.example.learnloop.ui.viewmodel

import androidx.lifecycle.ViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update

data class SummarySection(
    val title: String,
    val items: List<String>,
    val numbered: Boolean = false
)

data class SessionSummaryUiState(
    val rating: Int = 0,
    val comment: String = "",
    val isTutor: Boolean = true,
    val sessionSubtitle: String = "45 minutes  ·  BST Deletion",
    val summarySections: List<SummarySection> = emptyList()
)

class SessionSummaryViewModel(
    repository: com.example.learnloop.data.repository.LearnLoopRepository
) : ViewModel() {
    private val _uiState = MutableStateFlow(
        SessionSummaryUiState(
            summarySections = listOf(
                SummarySection(
                    title = "Key Concepts Covered",
                    items = listOf(
                        "Binary Search Tree deletion algorithm",
                        "In-order successor concept",
                        "Three cases: no child, one child, two children",
                        "Time complexity: O(h) where h = height"
                    )
                ),
                SummarySection(
                    title = "Code / Notes Shared",
                    items = listOf(
                        "BST delete() pseudocode walkthrough",
                        "findMin() helper function",
                        "Recursive deletion implementation"
                    )
                ),
                SummarySection(
                    title = "3 Takeaways",
                    items = listOf(
                        "Always find the in-order successor (smallest in right subtree) for two-child deletion.",
                        "The in-order successor has at most one right child, simplifying its own deletion.",
                        "For balanced BSTs: O(log n), but O(n) worst-case for skewed trees."
                    ),
                    numbered = true
                )
            )
        )
    )
    val uiState: StateFlow<SessionSummaryUiState> = _uiState.asStateFlow()

    fun onRatingChange(value: Int) {
        _uiState.update { it.copy(rating = value) }
    }

    fun onCommentChange(value: String) {
        _uiState.update { it.copy(comment = value) }
    }
}
